void byValue(int x)        { x = 99; }   // local copy, caller unaffected
void byRef(int& x)         { x = 99; }   // modifies caller's variable
void byConstRef(const int& x) { /* x = 99; ERROR */ }  // read-only, no copy
void byPtr(int* x)         { if (x) *x = 99; }

int main() {
    int a = 10;
    byValue(a);     // a == 10
    byRef(a);       // a == 99
    byConstRef(a);  // a unchanged, no copy made
    byPtr(&a);      // a == 99

    // const variables
    const int MAX = 100;
    // MAX = 200;   // ERROR: assignment of read-only

    int x = 5, y = 10;
    int& ref = x;   // ref is an alias for x
    ref = y;        // copies y into x; ref STILL refers to x
}

#include <vector>
#include <iostream>

int main() {
    std::vector<int> nums = {1, 2, 3, 4, 5};

    // Range-based for (C++11) — preferred
    for (int n : nums) std::cout << n << ' ';

    // By const reference (no copies, read-only)
    for (const auto& n : nums) std::cout << n << ' ';

    // By reference (modify in place)
    for (auto& n : nums) n *= 2;

    // C++17: if with initializer (scoped variable)
    if (auto it = std::find(nums.begin(), nums.end(), 4); it != nums.end()) {
        std::cout << "Found at index " << (it - nums.begin()) << '\n';
    }

    // switch with fallthrough (C++17 [[fallthrough]] attribute)
    int x = 2;
    switch (x) {
        case 1: std::cout << "one"; break;
        case 2: [[fallthrough]];  // intentional, silences warning
        case 3: std::cout << "two or three"; break;
        default: std::cout << "other";
    }
}

