// Without RAII (C-style, error-prone)
void badRead(const char* path) {
    FILE* f = fopen(path, "r");
    if (!f) return;
    // ... what if an exception throws here? FILE leaks!
    fclose(f);
}

// With RAII
void goodRead(const std::string& path) {
    std::ifstream f(path);   // constructor opens file
    if (!f) return;
    // ... even if an exception throws, file is closed by destructor
}   // destructor runs here, closes f automatically

