#include <memory>
#include <iostream>

class Resource {
public:
    Resource()  { std::cout << "Resource acquired\n"; }
    ~Resource() { std::cout << "Resource released\n"; }
    void use()  { std::cout << "Using resource\n"; }
};

void uniqueExample() {
    auto p = std::make_unique<Resource>();   // sole owner
    p->use();
    // auto p2 = p;       // ERROR: unique_ptr is non-copyable
    auto p3 = std::move(p);  // OK: ownership transferred; p is now nullptr
}   // p3 destroyed → Resource released

void sharedExample() {
    auto p1 = std::make_shared<Resource>();   // ref count = 1
    {
        auto p2 = p1;                          // ref count = 2
    }                                          // ref count = 1
    std::cout << "Use count: " << p1.use_count() << '\n';
}   // ref count = 0 → Resource released

void weakExample() {
    auto shared = std::make_shared<int>(42);
    std::weak_ptr<int> weak = shared;
    if (auto locked = weak.lock()) {  // returns shared_ptr if alive, else nullptr
        std::cout << "Still alive: " << *locked << '\n';
    }
}

