// Account.cpp
#include "Account.h"
#include <stdexcept>

Account::Account(double initialBalance) : balance_(initialBalance) {
    if (initialBalance < 0) throw std::invalid_argument("Negative balance");
}

void Account::deposit(double amount) {
    balance_ += amount;
    ++transactionCount_;
}

bool Account::withdraw(double amount) {
    if (amount > balance_) return false;
    balance_ -= amount;
    ++transactionCount_;
    return true;
}

double Account::balance() const { return balance_; }

