class Shape {
public:
    virtual ~Shape() = default;             // CRITICAL: virtual destructor
    virtual double area() const = 0;        // pure virtual → abstract class
    virtual void   draw() const { std::cout << "Shape\n"; }
};

class Circle : public Shape {
    double radius_;
public:
    explicit Circle(double r) : radius_(r) {}
    double area() const override { return 3.14159 * radius_ * radius_; }
    void   draw() const override { std::cout << "Circle(r=" << radius_ << ")\n"; }
};

class Square : public Shape {
    double side_;
public:
    explicit Square(double s) : side_(s) {}
    double area() const override { return side_ * side_; }
    void   draw() const override { std::cout << "Square(s=" << side_ << ")\n"; }
};

