    std::vector<std::unique_ptr<Shape>> shapes;
    shapes.push_back(std::make_unique<Circle>(3));
    shapes.push_back(std::make_unique<Square>(4));

    for (const auto& s : shapes) {
        s->draw();                          // virtual dispatch
        std::cout << "Area: " << s->area() << '\n';
    }
}   // unique_ptrs destroyed → virtual destructor → correct subclass cleanup

#include <iostream>
#include <compare>

class Vec2 {
    double x_, y_;
public:
    Vec2(double x = 0, double y = 0) : x_(x), y_(y) {}

    // Arithmetic
    Vec2 operator+(const Vec2& o) const { return {x_+o.x_, y_+o.y_}; }
    Vec2 operator-(const Vec2& o) const { return {x_-o.x_, y_-o.y_}; }
    Vec2 operator*(double s)        const { return {x_*s, y_*s}; }

    // Compound assignment
    Vec2& operator+=(const Vec2& o) { x_+=o.x_; y_+=o.y_; return *this; }

    // C++20 spaceship — generates ==, !=, <, <=, >, >= automatically
    auto operator<=>(const Vec2&) const = default;

    // Stream output (must be a free function or friend)
    friend std::ostream& operator<<(std::ostream& os, const Vec2& v) {
        return os << '(' << v.x_ << ", " << v.y_ << ')';
    }
};

int main() {
    Vec2 a(1, 2), b(3, 4);
    Vec2 c = a + b * 2;
    std::cout << c << '\n';        // (7, 10)
    std::cout << (a == b) << '\n'; // 0 (from <=> = default)
}

