int main() {
    // vector — your default container
    std::vector<int> v = {1, 2, 3};
    v.push_back(4);                // append: 1 2 3 4
    v.insert(v.begin() + 1, 99);   // insert at index 1: 1 99 2 3 4
    v.erase(v.begin());            // remove first: 99 2 3 4
    std::cout << v.size() << ' ' << v.capacity() << '\n';
    v.reserve(1000);               // pre-allocate to avoid reallocations

    // array — fixed size, on the stack
    std::array<int, 5> a = {1, 2, 3, 4, 5};
    std::cout << a.size() << '\n'; // 5 (compile-time)

    // deque — fast front + back operations
    std::deque<int> d = {2, 3};
    d.push_front(1);               // 1 2 3
    d.push_back(4);                // 1 2 3 4

    // list — doubly-linked, rare in practice
    std::list<int> l = {1, 2, 3};
    auto it = l.begin();
    ++it;
    l.insert(it, 99);              // 1 99 2 3 (no reallocation, but cache-unfriendly)
}

