int main() {
    // map — sorted by key, O(log n)
    std::map<std::string, int> ages;
    ages["Alice"] = 30;
    ages["Bob"]   = 25;
    ages.insert({"Carol", 35});

    // C++17 structured binding — clean iteration
    for (const auto& [name, age] : ages) {
        std::cout << name << ": " << age << '\n';   // iterates in sorted key order
    }

    // contains() (C++20) or find()
    if (ages.contains("Alice")) { /* ... */ }
    if (auto it = ages.find("Bob"); it != ages.end()) {
        std::cout << it->second << '\n';
    }

    // unordered_map — hash-based, O(1) average
    std::unordered_map<std::string, int> scores = {{"a", 1}, {"b", 2}};
    scores["c"] = 3;

    // set — unique sorted values
    std::set<int> s = {3, 1, 4, 1, 5, 9, 2};   // duplicates discarded
    for (int x : s) std::cout << x << ' ';      // 1 2 3 4 5 9

    // try_emplace — efficient: doesn't construct value if key exists
    ages.try_emplace("Alice", 99);   // no-op since Alice exists
}

