#include <algorithm>
#include <numeric>
#include <vector>
#include <iostream>
#include <string>

int main() {
    std::vector<int> v = {5, 2, 8, 1, 9, 3, 7, 4, 6};

    // sort — in place, O(n log n)
    std::sort(v.begin(), v.end());           // ascending
    std::sort(v.begin(), v.end(), std::greater<>{}); // descending

    // find — linear search, returns iterator
    auto it = std::find(v.begin(), v.end(), 7);
    if (it != v.end()) std::cout << "Found at index " << (it - v.begin()) << '\n';

    // binary_search on sorted range — O(log n)
    std::sort(v.begin(), v.end());
    bool found = std::binary_search(v.begin(), v.end(), 7);

    // count, count_if
    int evens = std::count_if(v.begin(), v.end(),
                              [](int x) { return x % 2 == 0; });

    // transform — apply function, write to output
    std::vector<int> squared(v.size());
    std::transform(v.begin(), v.end(), squared.begin(),
                   [](int x) { return x * x; });

    // accumulate (in <numeric>) — reduce / fold
    int sum = std::accumulate(v.begin(), v.end(), 0);
    int product = std::accumulate(v.begin(), v.end(), 1, std::multiplies<>{});

    // all_of / any_of / none_of
    bool allPositive = std::all_of(v.begin(), v.end(),
                                   [](int x) { return x > 0; });

    // erase-remove idiom — remove all evens
    v.erase(std::remove_if(v.begin(), v.end(),
                           [](int x) { return x % 2 == 0; }),
            v.end());
}

