#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3, 4, 5};
    int threshold = 3;

    // Capture by value — copies threshold into the lambda
    auto countAbove = std::count_if(v.begin(), v.end(),
        [threshold](int x) { return x > threshold; });
    std::cout << countAbove << '\n';   // 2 (4 and 5)

    // Capture by reference — sum modifies outer variable
    int sum = 0;
    std::for_each(v.begin(), v.end(),
        [&sum](int x) { sum += x; });
    std::cout << sum << '\n';          // 15

    // mutable — allows modifying by-value capture
    int counter = 0;
    auto bump = [counter]() mutable { ++counter; return counter; };
    bump(); bump();
    // outer 'counter' is still 0 — bumped only the lambda's copy

    // Generic lambda (C++14)
    auto print = [](const auto& x) { std::cout << x << '\n'; };
    print(42); print("hi"); print(3.14);

    // Init-capture (C++14) — useful for moving into a lambda
    auto p = std::make_unique<int>(99);
    auto holder = [ptr = std::move(p)] { return *ptr; };
}

