class Buffer {
    std::vector<char> data_;
public:
    Buffer(size_t n) : data_(n) {}

    // Copy: deep copy of data — expensive
    Buffer(const Buffer& o) : data_(o.data_) {
        std::cout << "COPY of " << o.data_.size() << " bytes\n";
    }

    // Move: steal the source's internals — cheap (O(1))
    Buffer(Buffer&& o) noexcept : data_(std::move(o.data_)) {
        std::cout << "MOVE\n";
    }
};

Buffer makeBuffer() {
    Buffer b(1'000'000);   // big buffer
    return b;              // return by value — moves out (or RVO)
}

int main() {
    Buffer a = makeBuffer();    // MOVE (or no-op via copy elision)
    Buffer b = a;               // COPY — a still in use
    Buffer c = std::move(a);    // MOVE — a is now in 'moved-from' state
    // a is still valid but unspecified — only safe to assign to or destroy
}

