// Forwarding reference: T is deduced, && becomes 'forwarding'
template <typename T>
void process(T&& arg) {
    // Forwards 'arg' as the same value category it was passed as
    doWork(std::forward<T>(arg));
}

// Real-world example: emplace_back forwards args to T's constructor
struct Person {
    std::string name;
    int age;
    Person(std::string n, int a) : name(std::move(n)), age(a) {}
};

int main() {
    std::vector<Person> people;

    // push_back: must construct a temporary Person, then move/copy it in
    people.push_back(Person("Alice", 30));

    // emplace_back: forwards args directly to Person's constructor — no temp
    people.emplace_back("Bob", 25);

    // make_unique forwards to T's constructor
    auto p = std::make_unique<Person>("Carol", 35);
}

