// constexpr — usable at compile time AND runtime
constexpr int factorial(int n) {
    return n <= 1 ? 1 : n * factorial(n - 1);
}

static_assert(factorial(5) == 120, "Computed at compile time!");

// noexcept — promise not to throw
void swap_ints(int& a, int& b) noexcept {
    int tmp = a; a = b; b = tmp;
