}

// if constexpr — compile-time branching in templates
template <typename T>
auto getValue(T x) {
    if constexpr (std::is_pointer_v<T>) {
        return *x;       // only compiled when T is a pointer
    } else {
        return x;        // only compiled otherwise
    }
}

