#include <iostream>
#include <stdexcept>

template <typename T>
class Stack {
    static constexpr size_t MAX = 100;
    T      data_[MAX];
    size_t size_ = 0;
public:
    void push(const T& value) {
        if (size_ >= MAX) throw std::overflow_error("Stack full");
        data_[size_++] = value;
    }
    T pop() {
        if (size_ == 0) throw std::underflow_error("Empty stack");
        return data_[--size_];
    }
    bool empty() const { return size_ == 0; }
    size_t size() const { return size_; }
};

int main() {
    Stack<int> s;
    s.push(1); s.push(2); s.push(3);
    while (!s.empty()) std::cout << s.pop() << ' ';   // 3 2 1

    Stack<std::string> ss;
    ss.push("hello");
    ss.push("world");
}

#include <iostream>

// Recursive variadic template (classic style)
void print() { std::cout << '\n'; }

template <typename T, typename... Rest>
void print(const T& first, const Rest&... rest) {
    std::cout << first << ' ';
    print(rest...);   // recursive expansion
}

// C++17 fold expression — much cleaner
template <typename... Args>
void printFold(const Args&... args) {
    ((std::cout << args << ' '), ...);   // unary fold over comma
    std::cout << '\n';
}

// Sum any number of arguments
template <typename... Args>
auto sum(Args... args) {
    return (args + ...);   // unary fold over +
}

int main() {
    print(1, "hello", 3.14, 'A');
    printFold("x", 42, 9.99);
    std::cout << sum(1, 2, 3, 4, 5) << '\n';   // 15
}

#include <concepts>
#include <iostream>

// Define a concept
template <typename T>
concept Addable = requires(T a, T b) {
    { a + b } -> std::same_as<T>;
};

// Use a concept as a constraint
template <Addable T>
T sum(T a, T b) { return a + b; }

// Standard library concept
template <std::integral T>
T square(T x) { return x * x; }

// Multiple constraints
template <typename T>
requires std::integral<T> || std::floating_point<T>
T abs(T x) { return x < 0 ? -x : x; }

int main() {
    sum(1, 2);          // OK: int satisfies Addable
    sum(1.5, 2.5);      // OK: double satisfies Addable
    // sum("a", "b");   // ERROR: clear message about Addable failing
    square(5);          // OK
    // square(5.0);     // ERROR: not integral
}

#include <iostream>
#include <stdexcept>
#include <string>

class DatabaseError : public std::runtime_error {
public:
    DatabaseError(const std::string& msg) : std::runtime_error(msg) {}
};

int readFromDb(int id) {
    if (id < 0) throw std::invalid_argument("Negative ID");
    if (id == 999) throw DatabaseError("Connection lost");
    return id * 10;
}

int main() {
    try {
        std::cout << readFromDb(5)   << '\n';
        std::cout << readFromDb(-1)  << '\n';
    } catch (const DatabaseError& e) {       // most derived first
        std::cerr << "DB: " << e.what() << '\n';
    } catch (const std::invalid_argument& e) {
        std::cerr << "Invalid: " << e.what() << '\n';
    } catch (const std::exception& e) {       // catch-all for std::exception
        std::cerr << "Error: " << e.what() << '\n';
    } catch (...) {                           // catch absolutely everything
        std::cerr << "Unknown error\n";
    }
}

#include <vector>
#include <utility>

class Inventory {
    std::vector<int> items_;
public:
    // Strong guarantee via copy-and-swap
    void replaceAll(const std::vector<int>& newItems) {
        std::vector<int> tmp = newItems;     // may throw — original unchanged
        items_.swap(tmp);                     // noexcept — commit step
    }   // tmp destructor runs (now holds the OLD items)

    // Basic guarantee
    void add(int x, int y) {
        items_.push_back(x);   // could throw bad_alloc
        items_.push_back(y);   // if THIS throws, x already added (basic, not strong)
    }

    // Strong guarantee version
    void addPair(int x, int y) {
        items_.reserve(items_.size() + 2);  // throws here? no commit
        items_.push_back(x);                // can't throw (capacity reserved)
        items_.push_back(y);                // can't throw
    }
};

#include <optional>
#include <variant>
#include <string>
#include <iostream>

// Pattern 1: optional — value or nothing
std::optional<int> parseInt(const std::string& s) {
    try { return std::stoi(s); }
    catch (...) { return std::nullopt; }
}

// Pattern 2: variant — value OR specific error
struct ParseError { std::string message; int position; };
std::variant<int, ParseError> parseStrict(const std::string& s) {
    try { return std::stoi(s); }
    catch (...) { return ParseError{"Not a number", 0}; }
}

// Pattern 3: std::expected (C++23) — like Rust's Result<T, E>
// std::expected<int, std::string> parse(const std::string& s);

int main() {
    if (auto n = parseInt("42")) {
        std::cout << *n << '\n';
    } else {
        std::cout << "Failed\n";
    }

    auto result = parseStrict("hello");
    if (auto* val = std::get_if<int>(&result)) {
        std::cout << "OK: " << *val << '\n';
    } else if (auto* err = std::get_if<ParseError>(&result)) {
        std::cout << "Err: " << err->message << '\n';
    }
}

#include <vector>
#include <iostream>

class Widget {
public:
    Widget() = default;

    Widget(const Widget&) { std::cout << "COPY\n"; }   // may throw
    Widget& operator=(const Widget&) { std::cout << "COPY=\n"; return *this; }

    Widget(Widget&&) noexcept { std::cout << "MOVE\n"; }   // noexcept
    Widget& operator=(Widget&&) noexcept { std::cout << "MOVE=\n"; return *this; }

    ~Widget() = default;   // implicitly noexcept
};

int main() {
    std::vector<Widget> v;
    v.reserve(2);
    v.emplace_back();   // capacity = 2
    v.emplace_back();   // capacity = 2
    v.emplace_back();   // EXCEEDS — vector reallocates → uses MOVE because noexcept
}

// If Widget's move ctor were NOT noexcept, the vector would COPY all elements
// during reallocation to preserve strong exception safety.

#include <thread>
#include <iostream>
#include <vector>
#include <chrono>

void worker(int id) {
    std::cout << "Worker " << id << " started\n";
    std::this_thread::sleep_for(std::chrono::milliseconds(100));
    std::cout << "Worker " << id << " done\n";
}

int main() {
    // Single thread
    std::thread t1(worker, 1);
    t1.join();   // wait for it

    // Multiple threads with lambda
    std::vector<std::thread> threads;
    for (int i = 0; i < 4; ++i) {
        threads.emplace_back([i] {
            std::cout << "Thread " << i << " with TID "
                      << std::this_thread::get_id() << '\n';
        });
    }
    for (auto& t : threads) t.join();

    // C++20 jthread — auto-joins on destruction
    {
        std::jthread jt([](std::stop_token stop) {
            while (!stop.stop_requested()) {
                std::this_thread::sleep_for(std::chrono::milliseconds(10));
            }
        });
        std::this_thread::sleep_for(std::chrono::milliseconds(50));
        // jt destructor calls request_stop() then joins automatically
    }
}

#include <mutex>
#include <shared_mutex>
#include <thread>
#include <vector>
#include <iostream>

class Counter {
    int count_ = 0;
    mutable std::shared_mutex mtx_;   // mutable: lockable in const methods
public:
    void increment() {
        std::unique_lock lock(mtx_);   // exclusive (writer)
        ++count_;
    }
    int get() const {
        std::shared_lock lock(mtx_);   // shared (multiple readers OK)
        return count_;
    }
};

int main() {
    Counter c;
    std::vector<std::jthread> ts;
    for (int i = 0; i < 8; ++i) {
        ts.emplace_back([&] {
            for (int j = 0; j < 1000; ++j) c.increment();
        });
    }
    // jthreads auto-join here
    for (auto& t : ts) t.join();
    std::cout << c.get() << '\n';   // 8000
}

