#include <atomic>
#include <thread>
#include <vector>
#include <iostream>

std::atomic<int> counter{0};
std::atomic<bool> ready{false};

void producer() {
    counter.store(42, std::memory_order_release);
    ready.store(true, std::memory_order_release);
}

void consumer() {
    while (!ready.load(std::memory_order_acquire)) {
        std::this_thread::yield();
    }
    // Acquire-release ensures we see counter == 42 here
    std::cout << counter.load(std::memory_order_relaxed) << '\n';
}

int main() {
    // Simple counter — no manual mutex needed
    std::atomic<int> hits{0};
    std::vector<std::jthread> ts;
    for (int i = 0; i < 10; ++i) {
        ts.emplace_back([&] {
            for (int j = 0; j < 1000; ++j) hits.fetch_add(1);
        });
    }
    for (auto& t : ts) t.join();
    std::cout << hits.load() << '\n';   // exactly 10000
}

#include <future>
#include <iostream>
#include <chrono>

int slowComputation(int x) {
    std::this_thread::sleep_for(std::chrono::milliseconds(100));
    return x * x;
}

int main() {
    // std::async — fire-and-forget computation
    std::future<int> f1 = std::async(std::launch::async, slowComputation, 7);
    std::future<int> f2 = std::async(std::launch::async, slowComputation, 8);

    // ... do other work ...

    int result = f1.get() + f2.get();   // blocks until each ready
    std::cout << result << '\n';        // 49 + 64 = 113

    // Promise / future pair — manual signaling between threads
    std::promise<std::string> p;
    std::future<std::string> f = p.get_future();

    std::jthread producer([&] {
        std::this_thread::sleep_for(std::chrono::milliseconds(50));
        p.set_value("Hello from another thread!");
    });

    std::cout << f.get() << '\n';   // blocks until set_value
}

// CLASSIC DEADLOCK
std::mutex a, b;
void t1() { std::lock_guard la(a); std::lock_guard lb(b); /* ... */ }
void t2() { std::lock_guard lb(b); std::lock_guard la(a); /* ... */ }
//   t1 holds a, waits for b
//   t2 holds b, waits for a
//   → deadlock

// FIX 1: always acquire locks in the same order
// FIX 2: use std::scoped_lock(a, b) — handles ordering for you
void t1_fixed() { std::scoped_lock l(a, b); /* ... */ }
void t2_fixed() { std::scoped_lock l(b, a); /* ... */ }   // OK!

