// Compile with sanitizers in CI:
// g++ -std=c++20 -fsanitize=thread -g program.cpp

// CLASSIC UB EXAMPLES — all of these are bugs

// 1. Signed overflow is UB (unsigned overflow is well-defined wrap)
int x = INT_MAX;
x + 1;   // UB! Compilers exploit this for optimization.

// 2. Dereferencing nullptr
int* p = nullptr;
*p = 5;   // UB → typically segfault

// 3. Dangling reference
std::string& f() {
    std::string s = "hi";
    return s;   // UB! s destroyed at scope exit
}

// 4. Out of bounds
std::vector<int> v = {1, 2, 3};
int x = v[10];   // UB! use at() to throw instead

// 5. Use after free
int* p2 = new int(5);
delete p2;
int y = *p2;   // UB!

// 6. Reading uninitialized
int u;
std::cout << u;   // UB!

// 7. Modifying string literal
char* s = const_cast<char*>("hello");
s[0] = 'H';   // UB!

