// Example: small functions get inlined
inline int square(int x) { return x * x; }   // 'inline' is mostly a hint

// Example: branchless idiom often beats branchy
int absBranchy(int x) { return x < 0 ? -x : x; }   // branch
int absBranchless(int x) {
    int mask = x >> 31;          // -1 if negative, 0 otherwise
    return (x ^ mask) - mask;
}

