// AoS — Array of Structures (intuitive but cache-unfriendly for column-wise ops)
struct ParticleAoS {
    float x, y, z;
    float vx, vy, vz;
    float mass;
    bool  alive;
};
std::vector<ParticleAoS> particlesAoS;

// SoA — Structure of Arrays (often faster for SIMD / column ops)
struct ParticlesSoA {
    std::vector<float> x, y, z;
    std::vector<float> vx, vy, vz;
    std::vector<float> mass;
    std::vector<bool>  alive;
};

// Updating positions: SoA is friendly to SIMD
void updateSoA(ParticlesSoA& p, float dt) {
    for (size_t i = 0; i < p.x.size(); ++i) {
        p.x[i] += p.vx[i] * dt;
        p.y[i] += p.vy[i] * dt;
        p.z[i] += p.vz[i] * dt;
    }
}

