// Google Benchmark example
#include <benchmark/benchmark.h>
#include <vector>
#include <list>
#include <numeric>

static void BM_VectorSum(benchmark::State& state) {
    std::vector<int> v(state.range(0));
    std::iota(v.begin(), v.end(), 0);
    for (auto _ : state) {
        long sum = 0;
        for (int x : v) sum += x;
        benchmark::DoNotOptimize(sum);   // prevent dead-code elimination
    }
}
BENCHMARK(BM_VectorSum)->Range(1<<10, 1<<20);

static void BM_ListSum(benchmark::State& state) {
    std::list<int> l(state.range(0));
    std::iota(l.begin(), l.end(), 0);
    for (auto _ : state) {
        long sum = 0;
        for (int x : l) sum += x;
        benchmark::DoNotOptimize(sum);
    }
}
BENCHMARK(BM_ListSum)->Range(1<<10, 1<<20);

BENCHMARK_MAIN();

